// Pull both ensures-conjuncts for r1 and r2 into the proof context so
// that Verus instantiates the two `forall|i|` quantifiers with matching
// triggers (the auto-chosen pattern `self_@[self_.keys@[i]]@`).
assert(r1.0 == (forall |i| #![auto] lo <= i <= hi ==> self_@[self_.keys@[i]]@ == v@));
assert(r2.0 == (forall |i| #![auto] lo <= i <= hi ==> self_@[self_.keys@[i]]@ == v@));

assert(!r1.0 ==> (r1.1 == (self_@[self_.keys@[hi as int]]@ != v@
    && (forall |i| #![auto] lo <= i < hi ==> self_@[self_.keys@[i]]@ == v@))));
assert(!r2.0 ==> (r2.1 == (self_@[self_.keys@[hi as int]]@ != v@
    && (forall |i| #![auto] lo <= i < hi ==> self_@[self_.keys@[i]]@ == v@))));

// Both r1.0 and r2.0 equal the same forall-expression over the same
// inputs, hence agree.
assert(r1.0 == r2.0);

// When .0 is false, both .1 values equal the same right-hand-side
// expression (which itself involves the second forall), hence agree.
assert(!r1.0 ==> r1.1 == r2.1);
assert(!r2.0 ==> r1.1 == r2.1);
